// Default language
const DEFAULT_LANGUAGE = 'zh-CN';

// Language storage key
const STORAGE_KEY = 'kalana_language';

// Current translations
let translations = {};

// Current language
let currentLanguage = DEFAULT_LANGUAGE;

// Loading status
let isLoading = false;

/**
 * Initialize i18n system
 */
async function initI18n() {
  console.log('[i18n] Initializing...');

  const savedLang = localStorage.getItem(STORAGE_KEY);

  if (savedLang && SUPPORTED_LANGUAGES.some(l => l.code === savedLang)) {
    currentLanguage = savedLang;
    console.log('[i18n] Using saved language:', currentLanguage);
  } else {
    currentLanguage = getBrowserLanguage();
    console.log('[i18n] Using browser language:', currentLanguage);
  }

  await loadTranslations(currentLanguage);
  applyTranslations();
  updateLanguageSelector();
  document.documentElement.lang = currentLanguage;

  console.log('[i18n] Initialization complete');
}

/**
 * Get browser's preferred language
 */
function getBrowserLanguage() {
  const browserLang = navigator.language || navigator.userLanguage || '';
  console.log('[i18n] Browser language:', browserLang);

  if (SUPPORTED_LANGUAGES.some(l => l.code === browserLang)) {
    return browserLang;
  }

  const langCode = browserLang.split('-')[0];
  const match = SUPPORTED_LANGUAGES.find(l =>
    l.code.startsWith(langCode) || langCode.startsWith(l.code.split('-')[0])
  );

  const result = match ? match.code : DEFAULT_LANGUAGE;
  console.log('[i18n] Matched language:', result);
  return result;
}

/**
 * Load translations from embedded ALL_TRANSLATIONS (no network request)
 */
async function loadTranslations(lang) {
  if (isLoading) return;
  isLoading = true;

  console.log('[i18n] Loading translations for:', lang);

  if (ALL_TRANSLATIONS[lang]) {
    translations = ALL_TRANSLATIONS[lang];
    currentLanguage = lang;
    console.log('[i18n] Translations loaded successfully for:', lang);
  } else {
    console.warn('[i18n] Language not found in embedded translations:', lang);
    if (lang !== DEFAULT_LANGUAGE) {
      console.log('[i18n] Falling back to default language:', DEFAULT_LANGUAGE);
      translations = ALL_TRANSLATIONS[DEFAULT_LANGUAGE] || {};
      currentLanguage = DEFAULT_LANGUAGE;
    }
  }

  isLoading = false;
}

/**
 * Get a translation by key (supports nested keys like 'nav.home')
 * Also handles array format: 'terms.account_req_l1' -> looks for 'terms.account_req_l[0]'
 */
function t(key) {
  const keys = key.split('.');
  let value = translations;

  // Try exact key lookup first
  for (const k of keys) {
    if (value && typeof value === 'object' && k in value) {
      value = value[k];
    } else {
      value = undefined;
      break;
    }
  }

  // If exact lookup found and returns a valid string, use it
  if (value && typeof value === 'string') {
    return value;
  }

  // If not found, try array format
  // For key like 'terms.account_req_l1', try to find 'terms.account_req_l[0]'
  const lastPart = keys[keys.length - 1];
  const match = lastPart.match(/^(.+?)(\d+)$/);

  if (match) {
    const baseKey = match[1]; // e.g., 'account_req_l'
    const index = parseInt(match[2]) - 1; // Convert 'l1' to index 0

    // Navigate to parent object
    let parent = translations;
    for (let i = 0; i < keys.length - 1; i++) {
      if (parent && typeof parent === 'object' && keys[i] in parent) {
        parent = parent[keys[i]];
      } else {
        parent = null;
        break;
      }
    }

    // Check if parent has the base array
    if (parent && typeof parent === 'object' && baseKey in parent) {
      const arr = parent[baseKey];
      if (Array.isArray(arr) && index >= 0 && index < arr.length) {
        return arr[index];
      }
    }
  }

  // Fallback: return the key itself if nothing found
  if (value === undefined) {
    console.warn('[i18n] Translation key not found:', key);
    return key;
  }

  return value;
}

/**
 * Apply translations to the page
 */
function applyTranslations() {
  console.log('[i18n] Applying translations...');
  console.log('[i18n] Current translations:', Object.keys(translations).length > 0 ? 'Loaded' : 'Empty');

  document.querySelectorAll('[data-i18n]').forEach(element => {
    const key = element.getAttribute('data-i18n');
    const translation = t(key);
    if (translation && typeof translation === 'string') {
      element.textContent = translation;
    }
  });

  document.querySelectorAll('[data-i18n-html]').forEach(element => {
    const key = element.getAttribute('data-i18n-html');
    const translation = t(key);
    if (translation) {
      element.innerHTML = translation;
    }
  });

  document.querySelectorAll('[data-i18n-placeholder]').forEach(element => {
    const key = element.getAttribute('data-i18n-placeholder');
    const translation = t(key);
    if (translation) {
      element.placeholder = translation;
    }
  });

  document.querySelectorAll('[data-i18n-title]').forEach(element => {
    const key = element.getAttribute('data-i18n-title');
    const translation = t(key);
    if (translation) {
      element.title = translation;
    }
  });

  const pageTitle = document.querySelector('title');
  if (pageTitle && translations.meta) {
    pageTitle.textContent = `${translations.meta.langName} - CoBudget`;
  }

  updateScreenshots();

  console.log('[i18n] Translations applied');
}

/**
 * Update screenshots based on current language
 */
function updateScreenshots() {
  const langInfo = SUPPORTED_LANGUAGES.find(l => l.code === currentLanguage);
  if (!langInfo) return;

  const basePath = `assets/images/${langInfo.dir}`;

  document.querySelectorAll('[data-screenshot]').forEach(img => {
    const num = img.getAttribute('data-screenshot');
    const index = parseInt(num) - 1;
    const filename = ['1', '2', '3', '4', '5'][index] || num;
    const ext = 'PNG';
    const altKeys = ['calendar', 'report', 'add_transaction', 'members', 'settings'];

    img.src = `${basePath}/${filename}.${ext}`;
    const altKey = `screenshots.${altKeys[index]}`;
    const altText = t(altKey);
    if (altText && typeof altText === 'string') {
      img.alt = altText;
    }
  });
}

/**
 * Change language
 */
async function changeLanguage(lang) {
  console.log('[i18n] Changing language to:', lang);

  if (!SUPPORTED_LANGUAGES.some(l => l.code === lang)) {
    console.log('[i18n] Language not supported:', lang);
    return;
  }

  if (lang === currentLanguage) {
    console.log('[i18n] Same language, no change needed');
    return;
  }

  localStorage.setItem(STORAGE_KEY, lang);
  await loadTranslations(lang);
  applyTranslations();
  updateLanguageSelector();
  document.documentElement.lang = lang;

  window.dispatchEvent(new CustomEvent('languageChanged', { detail: { language: lang } }));
}

/**
 * Update language selector UI
 */
function updateLanguageSelector() {
  const selector = document.getElementById('language-selector');
  if (!selector) {
    console.log('[i18n] Language selector not found');
    return;
  }

  const currentLang = SUPPORTED_LANGUAGES.find(l => l.code === currentLanguage);

  const currentDisplay = selector.querySelector('.current-lang');
  if (currentDisplay) {
    currentDisplay.textContent = currentLang ? `${currentLang.flag} ${currentLang.name}` : '🌐 Language';
  }

  const dropdown = selector.querySelector('.lang-dropdown');
  if (dropdown) {
    dropdown.innerHTML = SUPPORTED_LANGUAGES.map(lang => `
      <button class="lang-option ${lang.code === currentLanguage ? 'active' : ''}"
              onclick="changeLanguage('${lang.code}')"
              type="button">
        <span class="lang-flag">${lang.flag}</span>
        <span class="lang-name">${lang.name}</span>
      </button>
    `).join('');
  }
}

/**
 * Toggle language dropdown
 */
function toggleLanguageDropdown() {
  const selector = document.getElementById('language-selector');
  if (!selector) return;

  selector.classList.toggle('active');

  if (selector.classList.contains('active')) {
    const closeHandler = (e) => {
      if (!selector.contains(e.target)) {
        selector.classList.remove('active');
        document.removeEventListener('click', closeHandler);
      }
    };
    setTimeout(() => document.addEventListener('click', closeHandler), 0);
  }
}

// Initialize when DOM is ready
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initI18n);
} else {
  initI18n();
}

// Export for global use
window.i18n = {
  t,
  changeLanguage,
  getCurrentLanguage: () => currentLanguage,
  getSupportedLanguages: () => SUPPORTED_LANGUAGES
};

console.log('[i18n] Module loaded with embedded translations (no network requests)');
